(() => {
  if (window.__GLS_SCROLLPATH_GLOBAL_V4__) return;
  window.__GLS_SCROLLPATH_GLOBAL_V4__ = true;

  const clamp = (n, a, b) => Math.max(a, Math.min(b, n));
  const prefersReduced = () =>
    window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches;

  const mqMobile = window.matchMedia ? window.matchMedia("(max-width: 767px)") : null;
  const isMobile = () => (mqMobile ? mqMobile.matches : false);

  const easeInOutCubic = (t) =>
    t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;

  const parseNum = (v, fallback) => {
    const n = parseFloat(v);
    return Number.isFinite(n) ? n : fallback;
  };

  const items = [];
  let ticking = false;

  function unionBBox(els) {
    let x1 = Infinity, y1 = Infinity, x2 = -Infinity, y2 = -Infinity;
    els.forEach((el) => {
      if (!el) return;
      try {
        const b = el.getBBox();
        if (!Number.isFinite(b.x)) return;
        x1 = Math.min(x1, b.x);
        y1 = Math.min(y1, b.y);
        x2 = Math.max(x2, b.x + b.width);
        y2 = Math.max(y2, b.y + b.height);
      } catch (e) {}
    });
    if (x1 === Infinity) return null;
    return { x: x1, y: y1, w: x2 - x1, h: y2 - y1 };
  }

  function parseViewBox(vb) {
    if (!vb) return null;
    const p = vb.trim().split(/[ ,]+/).map(parseFloat);
    if (p.length < 4 || p.some((n) => !Number.isFinite(n))) return null;
    return { x: p[0], y: p[1], w: p[2], h: p[3] };
  }

  function findHost(wrapper) {
    return (
      wrapper.closest(".page-section") ||
      wrapper.closest("section[data-section-id]") ||
      wrapper.closest("section[data-test='page-section']") ||
      wrapper.closest("section[data-test=\"page-section\"]") ||
      wrapper.closest("section") ||
      wrapper.parentElement
    );
  }

  function getOpts(wrapper) {
    const d = wrapper.dataset;
    const mode = (d.glsMode || d.mode || "fill").toLowerCase();

    return {
      mode,
      startPadVh: parseNum(d.startPadVh, 0),
      endPadVh: parseNum(d.endPadVh, 0),
      dotRadius: d.dotRadius != null ? parseNum(d.dotRadius, 8) : null,
      dotColor: d.dotColor || null,
      fadeBand: clamp(parseNum(d.fadeBand, 0.10), 0.001, 0.49),
      minOpacity: parseNum(d.minOpacity, 0.15),
      flow: (d.flow || "ttb").toLowerCase(),
      mobilePadX: parseNum(d.mobilePadX ?? d.padX, 0.06),
      mobilePadTop: parseNum(d.mobilePadTop ?? d.padTop, 0.00),
      mobilePadBottom: parseNum(d.mobilePadBottom ?? d.padBottom, 0.00),
      mobileFocusX: clamp(parseNum(d.mobileFocusX, 0.5), 0, 1),
      mobilePar: d.mobilePar || null,
      desktopPar: d.desktopPar || null,
      mobileZoom: d.mobileZoom != null ? parseNum(d.mobileZoom, 1) : 1,
      panY: parseNum(d.panY, 0),
      mobilePanY: parseNum(d.mobilePanY ?? d.panY, 0),
      bandHeight: parseNum(d.bandHeight, 360),
      bandHeightMobile: parseNum(d.bandHeightMobile ?? d.bandHeight, 240),
      bandHeightVw: d.bandHeightVw != null ? parseNum(d.bandHeightVw, null) : null,
      bandHeightVwMobile: d.bandHeightVwMobile != null ? parseNum(d.bandHeightVwMobile, null) : null,
      bandShift: parseNum(d.bandShift, 0),
      bandShiftMobile: parseNum(d.bandShiftMobile ?? d.bandShift, 0),
      segStart: d.segStart != null ? clamp(parseNum(d.segStart, 0), 0, 1) : null,
      segEnd: d.segEnd != null ? clamp(parseNum(d.segEnd, 1), 0, 1) : null,
      mobileSegStart: d.mobileSegStart != null ? clamp(parseNum(d.mobileSegStart, 0), 0, 1) : null,
      mobileSegEnd: d.mobileSegEnd != null ? clamp(parseNum(d.mobileSegEnd, 1), 0, 1) : null,
    };
  }

  function normalizeDotted(dotted) {
    if (!dotted) return;
    const fill = dotted.getAttribute("fill") || dotted.style.fill;
    const stroke = dotted.getAttribute("stroke") || dotted.style.stroke;
    const strokeWidth = dotted.getAttribute("stroke-width") || dotted.style.strokeWidth;
    const dash = dotted.getAttribute("stroke-dasharray") || dotted.style.strokeDasharray;
    const linecap = dotted.getAttribute("stroke-linecap") || dotted.style.strokeLinecap;
    const hasStroke = stroke && stroke !== "none" && stroke !== "transparent";
    const hasFill = fill && fill !== "none" && fill !== "transparent";
    if (hasStroke) {
      if (hasFill) dotted.style.setProperty("fill", fill, "important");
      else dotted.style.setProperty("fill", "none", "important");
      dotted.style.setProperty("stroke", stroke, "important");
      if (strokeWidth) dotted.style.setProperty("stroke-width", strokeWidth, "important");
      if (dash) dotted.style.setProperty("stroke-dasharray", dash, "important");
      if (linecap) dotted.style.setProperty("stroke-linecap", linecap, "important");
    } else if (hasFill) {
      dotted.style.setProperty("fill", fill, "important");
      dotted.style.setProperty("stroke", "none", "important");
    }
    dotted.style.setProperty("opacity", "1", "important");
    dotted.style.setProperty("visibility", "visible", "important");
  }

  function computeReverseByFlow(guide, len, flow) {
    const a = guide.getPointAtLength(0);
    const b = guide.getPointAtLength(len);
    if (flow === "ltr") return a.x > b.x;
    if (flow === "rtl") return a.x < b.x;
    if (flow === "btt") return a.y < b.y;
    return a.y > b.y;
  }

  function applyMobileFrame(inst) {
    const { svg, guide, dotted, opts } = inst;
    const defaultMobilePar = inst.opts.mode === "band" ? "xMidYMid slice" : "xMidYMin slice";
    const par = opts.mobilePar || defaultMobilePar;
    svg.setAttribute("preserveAspectRatio", par);
    const b = unionBBox([guide, dotted]) || guide.getBBox();
    if (!b || !Number.isFinite(b.w) || !Number.isFinite(b.h)) return;
    const padX = opts.mobilePadX;
    const padTop = opts.mobilePadTop;
    const padBottom = opts.mobilePadBottom;
    let x = b.x - b.w * padX;
    let w = b.w * (1 + padX * 2);
    let y = b.y - b.h * padTop;
    let h = b.h * (1 + padTop + padBottom);
    const cx = x + w * opts.mobileFocusX;
    x = cx - w / 2;
    if (opts.mobileZoom && opts.mobileZoom !== 1) {
      const z = opts.mobileZoom;
      const midX = x + w / 2;
      const midY = y + h / 2;
      w = w * z;
      h = h * z;
      x = midX - w / 2;
      y = midY - h / 2;
    }
    if (opts.mobilePanY) y += h * opts.mobilePanY;
    svg.setAttribute("viewBox", `${x} ${y} ${w} ${h}`);
  }

  function restoreDesktopFrame(inst) {
    const { svg, _origViewBox, _origPAR } = inst;
    if (_origViewBox) svg.setAttribute("viewBox", _origViewBox);
    if (_origPAR) svg.setAttribute("preserveAspectRatio", _origPAR);
    if (inst.opts.mode === "band") {
      svg.setAttribute("preserveAspectRatio", inst.opts.desktopPar || "xMidYMid slice");
    } else if (inst.opts.desktopPar) {
      svg.setAttribute("preserveAspectRatio", inst.opts.desktopPar);
    }
    if (inst.opts.panY) {
      const vb = parseViewBox(svg.getAttribute("viewBox"));
      if (vb) {
        vb.y += vb.h * inst.opts.panY;
        svg.setAttribute("viewBox", `${vb.x} ${vb.y} ${vb.w} ${vb.h}`);
      }
    }
  }

  function applyBandPosition(inst) {
    if (inst.opts.mode !== "band" || !inst._anchor) return;
    const hostRect = inst.host.getBoundingClientRect();
    const aRect = inst._anchor.getBoundingClientRect();
    const baseTop = aRect.top - hostRect.top;
    inst.wrapper.style.setProperty("--gls-band-top", `${baseTop + inst.opts.bandShift}px`);
    inst.wrapper.style.setProperty("--gls-band-top-mobile", `${baseTop + inst.opts.bandShiftMobile}px`);
    if (inst.opts.bandHeightVw != null) {
      const vwMobile = inst.opts.bandHeightVwMobile ?? inst.opts.bandHeightVw;
      inst.wrapper.style.setProperty("--gls-band-height", `${inst.opts.bandHeightVw}vw`);
      inst.wrapper.style.setProperty("--gls-band-height-mobile", `${vwMobile}vw`);
    } else {
      inst.wrapper.style.setProperty("--gls-band-height", `${inst.opts.bandHeight}px`);
      inst.wrapper.style.setProperty("--gls-band-height-mobile", `${inst.opts.bandHeightMobile}px`);
    }
  }

  function recalc(inst) {
    applyBandPosition(inst);
    if (isMobile()) applyMobileFrame(inst);
    else restoreDesktopFrame(inst);
    normalizeDotted(inst.dotted);
    inst.len = inst.guide.getTotalLength();
    inst.reverse = computeReverseByFlow(inst.guide, inst.len, inst.opts.flow);
  }

  function progress(inst) {
    const scrollY = window.scrollY || window.pageYOffset || 0;
    const vh = window.innerHeight || 1;
    const top = inst.host.getBoundingClientRect().top + scrollY;
    const h = inst.host.offsetHeight || 1;
    const baseStart = top - vh;
    const baseEnd = top + h;
    const start = baseStart - inst.opts.startPadVh * vh;
    const end = baseEnd + inst.opts.endPadVh * vh;
    return clamp((scrollY - start) / Math.max(1, end - start), 0, 1);
  }

  function mapSegment(inst, tAfterReverse) {
    if (!isMobile() && inst.opts.segStart != null && inst.opts.segEnd != null) {
      const a = inst.opts.segStart, b = inst.opts.segEnd;
      return a + (b - a) * tAfterReverse;
    }
    if (isMobile() && inst.opts.mobileSegStart != null && inst.opts.mobileSegEnd != null) {
      const a = inst.opts.mobileSegStart, b = inst.opts.mobileSegEnd;
      return a + (b - a) * tAfterReverse;
    }
    return tAfterReverse;
  }

  function place(inst, t) {
    const tt = inst.reverse ? 1 - t : t;
    let u = clamp(tt, 0, 1);
    u = clamp(mapSegment(inst, u), 0, 1);
    const p = inst.guide.getPointAtLength(inst.len * u);
    inst.dot.setAttribute("cx", p.x);
    inst.dot.setAttribute("cy", p.y);
    const band = inst.opts.fadeBand;
    let op = 1;
    if (u < band) op = u / band;
    else if (u > 1 - band) op = (1 - u) / band;
    op = clamp(op, inst.opts.minOpacity, 1);
    inst.dot.style.opacity = String(op);
  }

  function initOne(wrapper) {
    if (wrapper.__glsInit) return;
    wrapper.__glsInit = true;
    const host = findHost(wrapper);
    if (!host) return;
    host.classList.add("gls-scrollpath-host");
    const svg = wrapper.querySelector("svg");
    const guide = wrapper.querySelector("[data-gls-guide]");
    const dot = wrapper.querySelector("[data-gls-dot]");
    const dotted = wrapper.querySelector("[data-gls-dotted]");
    if (!svg || !guide || !dot) return;
    const opts = getOpts(wrapper);
    let anchor = null;
    if (opts.mode === "band" && wrapper.parentElement) {
      anchor = document.createElement("span");
      anchor.className = "gls-scrollpath-anchor";
      anchor.style.cssText = "display:block;width:0;height:0;line-height:0;";
      wrapper.parentElement.insertBefore(anchor, wrapper);
    }
    if (wrapper.parentElement !== host) host.prepend(wrapper);
    const existingR = parseFloat(dot.getAttribute("r"));
    const r = Number.isFinite(opts.dotRadius)
      ? opts.dotRadius
      : (Number.isFinite(existingR) ? existingR : 8);
    dot.setAttribute("r", String(r));
    const existingFill = dot.getAttribute("fill");
    const fill = opts.dotColor || existingFill || "#05392F";
    dot.setAttribute("fill", fill);
    dot.style.setProperty("opacity", "1", "important");
    dot.style.setProperty("visibility", "visible", "important");
    const inst = {
      host,
      wrapper,
      svg,
      guide,
      dotted,
      dot,
      opts,
      len: 0,
      reverse: false,
      _origViewBox: svg.getAttribute("viewBox"),
      _origPAR: svg.getAttribute("preserveAspectRatio"),
      _anchor: anchor,
      _ro: null,
    };
    recalc(inst);
    place(inst, prefersReduced() ? 0 : easeInOutCubic(progress(inst)));
    if ("ResizeObserver" in window) {
      inst._ro = new ResizeObserver(() => {
        recalc(inst);
        requestUpdate();
      });
      inst._ro.observe(host);
      inst._ro.observe(svg);
      if (inst._anchor) inst._ro.observe(inst._anchor);
    }
    items.push(inst);
  }

  function initAll() {
    document.querySelectorAll("[data-gls-scrollpath]").forEach(initOne);
    requestUpdate();
  }

  function update() {
    ticking = false;
    if (prefersReduced()) return;
    for (const inst of items) place(inst, easeInOutCubic(progress(inst)));
  }

  function requestUpdate() {
    if (!ticking) {
      ticking = true;
      requestAnimationFrame(update);
    }
  }

  function recalcAll() {
    for (const inst of items) recalc(inst);
    requestUpdate();
  }

  window.addEventListener("scroll", requestUpdate, { passive: true });
  window.addEventListener("resize", recalcAll);
  document.addEventListener("DOMContentLoaded", initAll);
  window.addEventListener("load", recalcAll);

  document.addEventListener("mercury:load", () => {
    for (const inst of items) if (inst._ro) inst._ro.disconnect();
    items.length = 0;
    document.querySelectorAll("[data-gls-scrollpath]").forEach(el => (el.__glsInit = false));
    initAll();
    requestAnimationFrame(recalcAll);
  });
})();
